patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 68bf5c52814f..a014f42109ba 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -10617,7 +10617,15 @@ BoUpSLP::getEntryCost(const TreeEntry *E, ArrayRef<Value *> VectorizedVals,
   case Instruction::BitCast: {
     auto SrcIt = MinBWs.find(getOperandEntry(E, 0));
     Type *SrcScalarTy = VL0->getOperand(0)->getType();
-    auto *SrcVecTy = getWidenedType(SrcScalarTy, VL.size());
+    Type *SrcVecTy;
+    if (ScalarTy->isVectorTy()) {
+      // This is a special case, when we have a vector cast instruction in the
+      // scalar part of the tree. This may happen, when we estimate the cost of
+      // the tree for horizontal reductions.
+      SrcVecTy = SrcScalarTy;
+    } else {
+      SrcVecTy = getWidenedType(SrcScalarTy, VL.size());
+    }
     unsigned Opcode = ShuffleOrOp;
     unsigned VecOpcode = Opcode;
     if (!ScalarTy->isFPOrFPVectorTy() && !SrcScalarTy->isFPOrFPVectorTy() &&
@@ -11789,7 +11797,7 @@ InstructionCost BoUpSLP::getTreeCost(ArrayRef<Value *> VectorizedVals) {
       unsigned OriginalSz = DL->getTypeSizeInBits(DstTy);
       unsigned SrcSz =
           ReductionBitWidth == 0 ? BWIt->second.first : ReductionBitWidth;
-      if (OriginalSz != SrcSz) {
+      if (OriginalSz != SrcSz && !DstTy->isVectorTy()) {
         unsigned Opcode = Instruction::Trunc;
         if (OriginalSz > SrcSz)
           Opcode = BWIt->second.second ? Instruction::SExt : Instruction::ZExt;

